def get_version_message():
    version = macsypy.__version__
    py_vers = sys.version.replace('\n', ' ')
    # Robust attribute access
    solution = macsypy.solution if hasattr(macsypy, 'solution') else {}
    if isinstance(solution, dict):
        nx_ver = solution.get('nx', None)
    else:
        nx_ver = getattr(solution, 'nx', None)
    nx_ver_str = nx_ver.__version__ if nx_ver is not None else 'unknown'
    # citation handling
    citation = macsypy.__citation__
    if callable(citation):
        citation_str = citation()
    else:
        citation_str = citation
    vers_msg = f"""Macsyfinder {version}
using:
- Python {py_vers}
- NetworkX {nx_ver_str}
- Pandas {pd.__version__}

MacsyFinder is distributed under the terms of the GNU General Public License (GPLv3).
See the COPYING file for details.

If you use this software please cite:
{citation_str}
and don't forget to cite models used:
macsydata cite <model>
"""
    return vers_msg
